/**
 * Safely read and parse a JSON file
 * Validates file path to prevent path traversal attacks
 */
function safeReadJsonFile(filePath) {
  const resolvedPath = path.resolve(filePath);
  const projectRoot = path.resolve(process.cwd());

  // Prevent path traversal - ensure the resolved path is within the project root
  if (!resolvedPath.startsWith(projectRoot + path.sep) && resolvedPath !== projectRoot) {
    // Allow reading files exactly at project root level
    const relativeToRoot = path.relative(projectRoot, resolvedPath);
    if (relativeToRoot.startsWith('..') || path.isAbsolute(relativeToRoot)) {
      throw new Error(`Security: Path traversal detected. Resolved path "${resolvedPath}" is outside project root "${projectRoot}".`);
    }
  }

  if (!fs.existsSync(resolvedPath)) {
    throw new Error(`File not found: ${resolvedPath}`);
  }

  const content = fs.readFileSync(resolvedPath, 'utf8');
  try {
    return JSON.parse(content);
  } catch (e) {
    throw new Error(`Invalid JSON in ${resolvedPath}: ${e.message}`);
  }
}

/**
 * Safely write content to a file within the project directory
 */
function safeWriteFile(filePath, content) {
  const resolvedPath = path.resolve(filePath);
  const projectRoot = path.resolve(process.cwd());

  const relativeToRoot = path.relative(projectRoot, resolvedPath);
  if (relativeToRoot.startsWith('..') || path.isAbsolute(relativeToRoot)) {
    throw new Error(`Security: Cannot write outside project root. Path: "${resolvedPath}"`);
  }

  const dir = path.dirname(resolvedPath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true, mode: 0o755 });
  }

  fs.writeFileSync(resolvedPath, content, { encoding: 'utf8', mode: 0o644 });
}

/**
 * Generate SHA-256 checksum of a file
 */
function generateChecksum(filePath) {
  const resolvedPath = path.resolve(filePath);
  const content = fs.readFileSync(resolvedPath);
  return crypto.createHash('sha256').update(content).digest('hex');
}

/**
 * Execute a shell command safely using execFileSync to prevent command injection
 */
function safeExec(command, args = [], options = {}) {
  try {
    const defaultOptions = {
      encoding: 'utf8',
      stdio: 'pipe',
      timeout: 120000, // 2 minute timeout
      maxBuffer: 10 * 1024 * 1024 // 10MB max buffer
    };
    const mergedOptions = { ...defaultOptions, ...options };
    return execFileSync(command, args, mergedOptions);
  } catch (error) {
    if (error.killed) {
      throw new Error(`Command timed out: ${command} ${args.join(' ')}`);
    }
    throw error;
  }
}

/**
 * Log with timestamp and level
 */
function log(level, message) {
  const timestamp = new Date().toISOString();
  const levels = { INFO: '\x1b[36m', WARN: '\x1b[33m', ERROR: '\x1b[31m', SUCCESS: '\x1b[32m' };
  const color = levels[level] || '\x1b[0m';
  const sanitizedMessage = String(message).replace(/[\x00-\x08\x0B\x0C\x0E-\x1F]/g, '');
  console.log(`${color}[${timestamp}] [${level}] ${sanitizedMessage}\x1b[0m`);
}

