/**
 * Validate the integrity of package-lock.json
 * Checks structure, registry URLs, and integrity hashes
 */
function validateLockfile() {
  log('INFO', 'Validating package-lock.json integrity...');

  const lockfile = safeReadJsonFile(CONFIG.lockfileName);
  const packageJson = safeReadJsonFile(CONFIG.packageFileName);
  const issues = [];
  const warnings = [];

  // Check lockfile version
  if (!lockfile.lockfileVersion) {
    issues.push('Missing lockfileVersion field');
  } else if (lockfile.lockfileVersion < 2) {
    warnings.push(`Lockfile version ${lockfile.lockfileVersion} is outdated. Consider upgrading to v3 (npm 7+).`);
  }

  // Validate package name matches
  if (lockfile.name !== packageJson.name) {
    issues.push(`Package name mismatch: lockfile="${lockfile.name}" vs package.json="${packageJson.name}"`);
  }

  // Validate version matches
  if (lockfile.version !== packageJson.version) {
    warnings.push(`Version mismatch: lockfile="${lockfile.version}" vs package.json="${packageJson.version}"`);
  }

  // Check for resolved URLs pointing to unexpected registries
  const packages = lockfile.packages || {};
  const dependencies = lockfile.dependencies || {};

  function validateRegistryUrl(url, packageName) {
    if (!url) return;
    try {
      const parsedUrl = new URL(url);
      const isAllowed = CONFIG.allowedRegistries.some(registry => {
        const registryUrl = new URL(registry);
        return parsedUrl.hostname === registryUrl.hostname;
      });
      if (!isAllowed) {
        issues.push(`Package "${packageName}" resolves to unauthorized registry: ${parsedUrl.origin}`);
      }
    } catch (e) {
      issues.push(`Package "${packageName}" has invalid resolved URL: ${url}`);
    }
  }

  // Validate packages (lockfile v2/v3)
  for (const [pkgPath, pkgData] of Object.entries(packages)) {
    if (pkgPath === '') continue; // Root package
    validateRegistryUrl(pkgData.resolved, pkgPath);

    // Check integrity hash exists for non-local packages
    if (pkgData.resolved && !pkgData.integrity) {
      warnings.push(`Package "${pkgPath}" is missing integrity hash`);
    }

    // Validate integrity hash format
    if (pkgData.integrity) {
      const validHashPrefixes = ['sha512-', 'sha384-', 'sha256-', 'sha1-'];
      const hasValidPrefix = validHashPrefixes.some(prefix => pkgData.integrity.startsWith(prefix));
      if (!hasValidPrefix) {
        issues.push(`Package "${pkgPath}" has invalid integrity hash format`);
      }
      // Warn about weak hash algorithms
      if (pkgData.integrity.startsWith('sha1-')) {
        warnings.push(`Package "${pkgPath}" uses weak SHA-1 integrity hash. Consider regenerating lockfile.`);
      }
    }
  }

  // Validate dependencies (lockfile v1)
  function validateDeps(deps, parentPath = '') {
    for (const [name, data] of Object.entries(deps)) {
      const fullPath = parentPath ? `${parentPath} > ${name}` : name;
      validateRegistryUrl(data.resolved, fullPath);

      if (data.resolved && !data.integrity) {
        warnings.push(`Dependency "${fullPath}" is missing integrity hash`);
      }

      if (data.dependencies) {
        validateDeps(data.dependencies, fullPath);
      }
    }
  }

  if (Object.keys(dependencies).length > 0) {
    validateDeps(dependencies);
  }

  // Check that all package.json dependencies are in lockfile
  const allDeps = {
    ...packageJson.dependencies,
    ...packageJson.devDependencies,
    ...packageJson.optionalDependencies
  };

  for (const depName of Object.keys(allDeps)) {
    const inPackages = Object.keys(packages).some(p => p === `node_modules/${depName}`);
    const inDependencies = depName in dependencies;
    if (!inPackages && !inDependencies) {
      issues.push(`Dependency "${depName}" from package.json not found in lockfile`);
    }
  }

  // Report results
  if (warnings.length > 0) {
    log('WARN', `Found ${warnings.length} warning(s):`);
    warnings.forEach(w => log('WARN', `  - ${w}`));
  }

  if (issues.length > 0) {
    log('ERROR', `Found ${issues.length} issue(s):`);
    issues.forEach(i => log('ERROR', `  - ${i}`));
    return { valid: false, issues, warnings };
  }

  log('SUCCESS', 'Lockfile validation passed!');
  return { valid: true, issues: [], warnings };
}

/**
 * Audit dependencies for known vulnerabilities
 */
function auditDependencies() {
  log('INFO', 'Auditing dependencies for vulnerabilities...');

  try {
    const auditResult = safeExec('npm', ['audit', '--json', `--audit-level=${CONFIG.auditLevel}`]);
    const audit = JSON.parse(auditResult);

    const report = {
      timestamp: new Date().toISOString(),
      totalVulnerabilities: 0,
      vulnerabilities: {
        critical: 0,
        high: 0,
        moderate: 0,
        low: 0,
        info: 0
      },
      details: []
    };

    if (audit.metadata && audit.metadata.vulnerabilities) {
      report.vulnerabilities = audit.metadata.vulnerabilities;
      report.totalVulnerabilities = Object.values(audit.metadata.vulnerabilities)
        .reduce((sum, count) => sum + count, 0);
    }

    if (audit.vulnerabilities) {
      for (const [name, vuln] of Object.entries(audit.vulnerabilities)) {
        report.details.push({
          package: name,
          severity: vuln.severity,
          range: vuln.range,
          fixAvailable: vuln.fixAvailable,
          via: Array.isArray(vuln.via) ? vuln.via.map(v => typeof v === 'string' ? v : v.title) : []
        });
      }
    }

    // Save report
    const reportPath = path.join(CONFIG.reportDir, `audit-${Date.now()}.json`);
    safeWriteFile(reportPath, JSON.stringify(report, null, 2));
    log('INFO', `Audit report saved to ${reportPath}`);

    // Summary
    log('INFO', '--- Vulnerability Summary ---');
    log(report.vulnerabilities.critical > 0 ? 'ERROR' : 'INFO',
      `Critical: ${report.vulnerabilities.critical}`);
    log(report.vulnerabilities.high > 0 ? 'ERROR' : 'INFO',
      `High: ${report.vulnerabilities.high}`);
    log(report.vulnerabilities.moderate > 0 ? 'WARN' : 'INFO',
      `Moderate: ${report.vulnerabilities.moderate}`);
    log('INFO', `Low: ${report.vulnerabilities.low}`);
    log('INFO', `Info: ${report.vulnerabilities.info}`);

    const hasBlockingVulns = (() => {
      switch (CONFIG.auditLevel) {
        case 'critical': return report.vulnerabilities.critical > 0;
        case 'high': return report.vulnerabilities.critical + report.vulnerabilities.high > 0;
        case 'moderate': return report.vulnerabilities.critical + report.vulnerabilities.high + report.vulnerabilities.moderate > 0;
        default: return report.totalVulnerabilities > 0;
      }
    })();

    if (hasBlockingVulns) {
      log('ERROR', `Blocking vulnerabilities found at "${CONFIG.auditLevel}" level or above.`);
      return { passed: false, report };
    }

    log('SUCCESS', 'No blocking vulnerabilities found.');
    return { passed: true, report };

  } catch (error) {
    // npm audit exits with non-zero when vulnerabilities are found
    if (error.stdout) {
      try {
        const audit = JSON.parse(error.stdout);
        log('WARN', 'Vulnerabilities detected. Review npm audit output.');
        return { passed: false, report: audit };
      } catch (parseError) {
        // Fall through
      }
    }
    log('ERROR', `Audit failed: ${error.message}`);
    return { passed: false, report: null };
  }
}

/**
 * Sync package-lock.json with package.json
 * Ensures lockfile reflects current package.json state
 */
function syncLockfile() {
  log('INFO', 'Syncing package-lock.json with package.json...');

  // Store checksum before sync
  let checksumBefore = null;
  if (fs.existsSync(CONFIG.lockfileName)) {
    checksumBefore = generateChecksum(CONFIG.lockfileName);
  }

  try {
    // Run npm install to regenerate lockfile
    safeExec('npm', ['install', '--package-lock-only'], { stdio: 'inherit' });

    const checksumAfter = generateChecksum(CONFIG.lockfileName);

    if (checksumBefore === checksumAfter) {
      log('SUCCESS', 'Lockfile is already in sync with package.json.');
    } else {
      log('WARN', 'Lockfile was updated. Review changes before committing.');
      log('INFO', `Previous checksum: ${checksumBefore || 'N/A'}`);
      log('INFO', `New checksum: ${checksumAfter}`);
    }

    // Save checksum
    safeWriteFile(CONFIG.checksumFile, checksumAfter);

    return { synced: true, changed: checksumBefore !== checksumAfter };
  } catch (error) {
    log('ERROR', `Sync failed: ${error.message}`);
    return { synced: false, changed: false };
  }
}

/**
 * Generate a frozen lockfile report for deployment verification
 */
function freezeLockfile() {
  log('INFO', 'Generating frozen lockfile report...');

  const lockfile = safeReadJsonFile(CONFIG.lockfileName);
  const packageJson = safeReadJsonFile(CONFIG.packageFileName);
  const checksum = generateChecksum(CONFIG.lockfileName);

  const frozenReport = {
    generatedAt: new Date().toISOString(),
    projectName: packageJson.name,
    projectVersion: packageJson.version,
    nodeVersion: process.version,
    npmVersion: safeExec('npm', ['--version']).trim(),
    lockfileVersion: lockfile.lockfileVersion,
    lockfileChecksum: checksum,
    totalPackages: 0,
    directDependencies: {},
    allPackages: {}
  };

  // Collect all packages with their exact versions
  const packages = lockfile.packages || {};
  for (const [pkgPath, pkgData] of Object.entries(packages)) {
    if (pkgPath === '') continue;

    const pkgName = pkgPath.replace(/^node_modules\//, '');
    frozenReport.allPackages[pkgName] = {
      version: pkgData.version,
      resolved: pkgData.resolved,
      integrity: pkgData.integrity,
      dev: pkgData.dev || false,
      optional: pkgData.optional || false
    };
    frozenReport.totalPackages++;
  }

  // Mark direct dependencies
  const directDeps = {
    ...packageJson.dependencies,
    ...packageJson.devDependencies
  };

  for (const [name, range] of Object.entries(directDeps)) {
    const lockEntry = frozenReport.allPackages[name];
    frozenReport.directDependencies[name] = {
      requestedRange: range,
      resolvedVersion: lockEntry ? lockEntry.version : 'NOT FOUND',
      integrity: lockEntry ? lockEntry.integrity : null
    };
  }

  // Save frozen report
  const reportPath = path.join(CONFIG.reportDir, `frozen-${Date.now()}.json`);
  safeWriteFile(reportPath, JSON.stringify(frozenReport, null, 2));

  log('SUCCESS', `Frozen lockfile report generated: ${reportPath}`);
  log('INFO', `Total packages: ${frozenReport.totalPackages}`);
  log('INFO', `Direct dependencies: ${Object.keys(frozenReport.directDependencies).length}`);
  log('INFO', `Lockfile checksum (SHA-256): ${checksum}`);

  return frozenReport;
}

/**
 * Perform a clean CI install using the lockfile
 * Equivalent to `npm ci` with additional checks
 */
function ciInstall() {
  log('INFO', 'Performing clean CI install...');

  // Pre-flight checks
  if (!fs.existsSync(CONFIG.lockfileName)) {
    log('ERROR', 'package-lock.json not found. Cannot perform CI install.');
    process.exit(1);
  }

  if (!fs.existsSync(CONFIG.packageFileName)) {
    log('ERROR', 'package.json not found.');
    process.exit(1);
  }

  // Validate lockfile first
  const validation = validateLockfile();
  if (!validation.valid) {
    log('ERROR', 'Lockfile validation failed. Fix issues before CI install.');
    process.exit(1);
  }

  // Store lockfile checksum before install
  const checksumBefore = generateChecksum(CONFIG.lockfileName);

  try {
    // npm ci removes node_modules and installs exactly from lockfile
    log('INFO', 'Running npm ci...');
    safeExec('npm', ['ci'], { stdio: 'inherit', timeout: 300000 }); // 5 min timeout

    // Verify lockfile wasn't modified
    const checksumAfter = generateChecksum(CONFIG.lockfileName);
    if (checksumBefore !== checksumAfter) {
      log('ERROR', 'CRITICAL: package-lock.json was modified during npm ci!');
      log('ERROR', 'This indicates a mismatch between package.json and package-lock.json.');
      process.exit(1);
    }

    log('SUCCESS', 'CI install completed successfully.');
    log('INFO', `Lockfile checksum verified: ${checksumAfter}`);

    return { success: true, checksum: checksumAfter };
  } catch (error) {
    log('ERROR', `CI install failed: ${error.message}`);
    process.exit(1);
  }
}

/**
 * Check for dependency drift between environments
 * Compares current lockfile checksum against a stored reference
 */
function checkDrift(referenceChecksum) {
  log('INFO', 'Checking for dependency drift...');

  const currentChecksum = generateChecksum(CONFIG.lockfileName);

  // Try to load stored checksum if no reference provided
  if (!referenceChecksum) {
    if (fs.existsSync(CONFIG.checksumFile)) {
      referenceChecksum = fs.readFileSync(path.resolve(CONFIG.checksumFile), 'utf8').trim();
      log('INFO', `Loaded reference checksum from ${CONFIG.checksumFile}`);
    } else {
      log('WARN', 'No reference checksum found. Use "freeze" command to generate one.');
      log('INFO', `Current checksum: ${currentChecksum}`);
      return { drifted: false, currentChecksum, referenceChecksum: null };
    }
  }

  // Validate checksum format (should be hex SHA-256)
  if (!/^[a-f0-9]{64}$/i.test(referenceChecksum)) {
    log('ERROR', 'Invalid reference checksum format. Expected SHA-256 hex string.');
    return { drifted: true, currentChecksum, referenceChecksum };
  }

  if (currentChecksum === referenceChecksum) {
    log('SUCCESS', 'No dependency drift detected.');
    return { drifted: false, currentChecksum, referenceChecksum };
  }

  log('ERROR', 'Dependency drift detected!');
  log('ERROR', `Reference checksum: ${referenceChecksum}`);
  log('ERROR', `Current checksum:   ${currentChecksum}`);
  log('WARN', 'Run "sync" to update the lockfile, or investigate unexpected changes.');

  return { drifted: true, currentChecksum, referenceChecksum };
}

/**
 * Generate a comprehensive dependency report
 */
function generateReport() {
  log('INFO', 'Generating dependency report...');

  const lockfile = safeReadJsonFile(CONFIG.lockfileName);
  const packageJson = safeReadJsonFile(CONFIG.packageFileName);

  const report = {
    generatedAt: new Date().toISOString(),
    project: {
      name: packageJson.name,
      version: packageJson.version,
      description: packageJson.description
    },
    environment: {
      nodeVersion: process.version,
      npmVersion: safeExec('npm', ['--version']).trim(),
      platform: process.platform,
      arch: process.arch
    },
    lockfile: {
      version: lockfile.lockfileVersion,
      checksum: generateChecksum(CONFIG.lockfileName)
    },
    statistics: {
      totalPackages: 0,
      productionPackages: 0,
      devPackages: 0,
      optionalPackages: 0,
      directDependencies: 0,
      transitiveDependencies: 0
    },
    directDependencies: [],
    outdatedPackages: []
  };

  // Count packages
  const packages = lockfile.packages || {};
  const directDepNames = new Set([
    ...Object.keys(packageJson.dependencies || {}),
    ...Object.keys(packageJson.devDependencies || {}),
    ...Object.keys(packageJson.optionalDependencies || {})
  ]);

  for (const [pkgPath, pkgData] of Object.entries(packages)) {
    if (pkgPath === '') continue;

    report.statistics.totalPackages++;

    if (pkgData.dev) {
      report.statistics.devPackages++;
    } else if (pkgData.optional) {
      report.statistics.optionalPackages++;
    } else {
      report.statistics.productionPackages++;
    }

    const pkgName = pkgPath.replace(/^node_modules\//, '');
    if (directDepNames.has(pkgName)) {
      report.statistics.directDependencies++;
      report.directDependencies.push({
        name: pkgName,
        version: pkgData.version,
        type: pkgData.dev ? 'dev' : pkgData.optional ? 'optional' : 'production'
      });
    } else {
      report.statistics.transitiveDependencies++;
    }
  }

  // Check for outdated packages
  try {
    const outdatedOutput = safeExec('npm', ['outdated', '--json']);
    if (outdatedOutput.trim()) {
      const outdated = JSON.parse(outdatedOutput);
      for (const [name, info] of Object.entries(outdated)) {
        report.outdatedPackages.push({
          name,
          current: info.current,
          wanted: info.wanted,
          latest: info.latest,
          type: info.type
        });
      }
    }
  } catch (error) {
    // npm outdated exits with code 1 when outdated packages exist
    if (error.stdout) {
      try {
        const outdated = JSON.parse(error.stdout);
        for (const [name, info] of Object.entries(outdated)) {
          report.outdatedPackages.push({
            name,
            current: info.current,
            wanted: info.wanted,
            latest: info.latest,
            type: info.type
          });
        }
      } catch (parseError) {
        log('WARN', 'Could not parse outdated packages output.');
      }
    }
  }

  // Save report
  const reportPath = path.join(CONFIG.reportDir, `report-${Date.now()}.json`);
  safeWriteFile(reportPath, JSON.stringify(report, null, 2));

  // Print summary
  log('INFO', '=== Dependency Report ===');
  log('INFO', `Project: ${report.project.name}@${report.project.version}`);
  log('INFO', `Total packages: ${report.statistics.totalPackages}`);
  log('INFO', `  Production: ${report.statistics.productionPackages}`);
  log('INFO', `  Development: ${report.statistics.devPackages}`);
  log('INFO', `  Optional: ${report.statistics.optionalPackages}`);
  log('INFO', `Direct dependencies: ${report.statistics.directDependencies}`);
  log('INFO', `Transitive dependencies: ${report.statistics.transitiveDependencies}`);
  log('INFO', `Outdated packages: ${report.outdatedPackages.length}`);
  log('INFO', `Report saved to: ${reportPath}`);

  if (report.outdatedPackages.length > 0) {
    log('WARN', '--- Outdated Packages ---');
    report.outdatedPackages.forEach(pkg => {
      log('WARN', `  ${pkg.name}: ${pkg.current} → ${pkg.wanted} (latest: ${pkg.latest})`);
    });
  }

  return report;
}

