/**
 * Pre-deployment check - runs all validations
 */
function preDeployCheck() {
  log('INFO', '=== Pre-Deployment Check ===');

  const results = {
    validation: null,
    audit: null,
    drift: null,
    overall: true
  };

  // Step 1: Validate lockfile
  log('INFO', 'Step 1/3: Validating lockfile...');
  results.validation = validateLockfile();
  if (!results.validation.valid) {
    results.overall = false;
  }

  // Step 2: Audit dependencies
  log('INFO', 'Step 2/3: Auditing dependencies...');
  results.audit = auditDependencies();
  if (!results.audit.passed) {
    results.overall = false;
  }

  // Step 3: Check drift
  log('INFO', 'Step 3/3: Checking for drift...');
  results.drift = checkDrift();
  if (results.drift.drifted) {
    results.overall = false;
  }

  // Final verdict
  if (results.overall) {
    log('SUCCESS', '=== All pre-deployment checks passed! ===');
  } else {
    log('ERROR', '=== Pre-deployment checks FAILED ===');
    if (!results.validation.valid) log('ERROR', '  ✗ Lockfile validation failed');
    if (!results.audit.passed) log('ERROR', '  ✗ Security audit failed');
    if (results.drift.drifted) log('ERROR', '  ✗ Dependency drift detected');
  }

  return results;
}

